 219 |     /// Public wrapper for sending a signed Converse API request.
 220 |     /// Used by the thinker backend.
 221 |     pub async fn send_converse_request(&self, url: &str, body: &[u8]) -> Result<reqwest::Response> {
 222 |         self.send_request("POST", url, Some(body), "bedrock").await
 223 |     }
 224 | 
 225 |     fn validate_auth(&self) -> Result<()> {
 226 |         match &self.auth {
 227 |             BedrockAuth::BearerToken(key) => {
 228 |                 if key.is_empty() {
 229 |                     anyhow::bail!("Bedrock API key is empty");
 230 |                 }
 231 |             }
 232 |             BedrockAuth::SigV4(creds) => {
 233 |                 if creds.access_key_id.is_empty() || creds.secret_access_key.is_empty() {
 234 |                     anyhow::bail!("AWS credentials are incomplete");
 235 |                 }
 236 |             }
 237 |         }
 238 |         Ok(())
 239 |     }
