 511 |             // --- Z.AI / GLM (ON_DEMAND only, no us. prefix) ---
 512 |             "glm-5" => "zai.glm-5",
 513 |             "glm-4.7" => "zai.glm-4.7",
 514 |             "glm-4.7-flash" => "zai.glm-4.7-flash",
 515 | 
 516 |             // Pass through full model IDs unchanged
 517 |             other => other,
 518 |         }
 519 |     }
