 730 |     /// Estimate context window size based on model family
 731 |     fn estimate_context_window(model_id: &str, provider: &str) -> usize {
 732 |         let id = model_id.to_lowercase();
 733 |         if id.contains("anthropic") || id.contains("claude") {
 734 |             200_000
 735 |         } else if id.contains("nova-pro") || id.contains("nova-lite") || id.contains("nova-premier")
 736 |         {
 737 |             300_000
 738 |         } else if id.contains("nova-micro") || id.contains("nova-2") {
 739 |             128_000
 740 |         } else if id.contains("llama4") || id.contains("jamba") {
 741 |             256_000
 742 |         } else if id.contains("mistral") && !id.contains("large") && !id.contains("magistral") {
 743 |             32_000
 744 |         } else if id.contains("deepseek")
 745 |             || id.contains("llama3")
 746 |             || id.contains("mistral-large-3")
 747 |             || id.contains("magistral")
 748 |             || id.contains("qwen")
 749 |             || id.contains("kimi")
 750 |             || id.contains("glm")
 751 |             || id.contains("minimax")
 752 |             || id.contains("gemma")
 753 |             || id.contains("cohere")
 754 |             || id.contains("command")
 755 |             || id.contains("nemotron")
 756 |             || provider.to_lowercase().contains("amazon")
 757 |         {
 758 |             128_000
 759 |         } else {
 760 |             32_000
 761 |         }
 762 |     }
 763 | 
 764 |     /// Estimate max output tokens based on model family
 765 |     fn estimate_max_output(model_id: &str, _provider: &str) -> usize {
 766 |         let id = model_id.to_lowercase();
 767 |         if id.contains("claude-opus-4-6")
 768 |             || id.contains("claude-opus-4-5")
 769 |             || id.contains("claude-opus-4-1")
 770 |             || id.contains("claude-opus-4")
 771 |         {
 772 |             32_000
 773 |         } else if id.contains("claude-sonnet-4-6") {
 774 |             128_000
 775 |         } else if id.contains("claude-sonnet-4-5")
 776 |             || id.contains("claude-sonnet-4")
 777 |             || id.contains("claude-3-7")
 778 |         {
 779 |             64_000
 780 |         } else if id.contains("claude-haiku-4-5") {
 781 |             16_384
 782 |         } else if id.contains("claude") {
 783 |             8_192
 784 |         } else if id.contains("nova") {
 785 |             5_000
 786 |         } else if id.contains("deepseek") || id.contains("llama4") || id.contains("mistral-large-3")
 787 |         {
 788 |             16_384
 789 |         } else if id.contains("llama") {
 790 |             4_096
 791 |         } else if id.contains("mistral")
 792 |             || id.contains("mixtral")
 793 |             || id.contains("qwen")
 794 |             || id.contains("kimi")
 795 |         {
 796 |             8_192
 797 |         } else {
 798 |             // jamba and other models
 799 |             4_096
 800 |         }
 801 |     }
