1047 | #[async_trait]
1048 | impl Provider for BedrockProvider {
1049 |     fn name(&self) -> &str {
1050 |         "bedrock"
1051 |     }
1052 | 
1053 |     async fn list_models(&self) -> Result<Vec<ModelInfo>> {
1054 |         self.validate_auth()?;
1055 |         self.discover_models().await
1056 |     }
1057 | 
1058 |     async fn complete(&self, request: CompletionRequest) -> Result<CompletionResponse> {
1059 |         let model_id = Self::resolve_model_id(&request.model);
1060 | 
1061 |         tracing::debug!(
1062 |             provider = "bedrock",
1063 |             model = %model_id,
1064 |             original_model = %request.model,
1065 |             message_count = request.messages.len(),
1066 |             tool_count = request.tools.len(),
1067 |             "Starting Bedrock Converse request"
1068 |         );
1069 | 
1070 |         self.validate_auth()?;
1071 | 
1072 |         let (system_parts, messages) = Self::convert_messages(&request.messages);
1073 |         let tools = Self::convert_tools(&request.tools);
1074 | 
1075 |         let mut body = json!({
1076 |             "messages": messages,
1077 |         });
1078 | 
1079 |         if !system_parts.is_empty() {
1080 |             body["system"] = json!(system_parts);
1081 |         }
1082 | 
1083 |         // inferenceConfig
1084 |         let mut inference_config = json!({});
1085 |         if let Some(max_tokens) = request.max_tokens {
1086 |             inference_config["maxTokens"] = json!(max_tokens);
1087 |         } else {
1088 |             inference_config["maxTokens"] = json!(8192);
1089 |         }
1090 |         if let Some(temp) = request.temperature {
1091 |             inference_config["temperature"] = json!(temp);
1092 |         }
1093 |         if let Some(top_p) = request.top_p {
1094 |             inference_config["topP"] = json!(top_p);
1095 |         }
1096 |         body["inferenceConfig"] = inference_config;
1097 | 
1098 |         if let Some(service_tier) = Self::configured_service_tier() {
1099 |             tracing::debug!(
1100 |                 provider = "bedrock",
1101 |                 service_tier = %service_tier,
1102 |                 "Applying Bedrock service tier override"
1103 |             );
1104 |             body["additionalModelRequestFields"] = json!({
1105 |                 "service_tier": service_tier
1106 |             });
1107 |         }
1108 | 
1109 |         if !tools.is_empty() {
1110 |             body["toolConfig"] = json!({"tools": tools});
1111 |         }
1112 | 
